#include <bits/stdc++.h>
#define int long long
using namespace std;
int n;
int num[1005];
int ans;
int dp[1010][40400];
int vis[1010][40400];
int bfc[1010];
int xsxs;
void DP (int nowi) {
	for (int i = nowi - 1; i >= 1; i--) {
        if (!vis[i][num[i] - num[nowi] + 20200]) {
          dp[i][num[i] - num[nowi] + 20200]++;
          vis[i][num[i] - num[nowi] + 20200] = 1;
        }
        ans = (int)(ans + dp[i][num[i] - num[nowi] + 20200]) % 998244353;
        dp[nowi][num[i] - num[nowi] + 20200]=(int)(dp[nowi][num[i] - num[nowi] + 20200] + dp[i][num[i] - num[nowi] + 20200]) % 998244353;
    }
    return;
}
signed main () {
	ios::sync_with_stdio (0);
	cin.tie (0), cout.tie (0);
	cin >> n;
	for (int i = 1; i <= n; i++) {
		cin >> num[i];
	} 
	for (int i = 1; i <= n; i++) {
		DP (i);
	}
	cout << ans + n;
	return 0;
}
